def main():
    if not (BASE / ".py" / "205" / "core").exists():
        raise SystemExit("205 Intelligence SDK bulunamadı. Önce SDK kurulmalı.")
    for rel, content in FILES.items():
        path = BASE / rel
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8")
        py_compile.compile(str(path), doraise=True)
    print("="*80)
    print("205.6-205.10 INTELLIGENCE BATCH BUILDER FIXED TAMAMLANDI")
    print("="*80)
    print("Oluşturulan dosya sayısı :", len(FILES))
    print("Run All dosyası          :", BASE / ".py" / "205_Intelligence_Run_All.py")
    print("")
    print("Şimdi çalıştır:")
    print(r'python ".py\205_Intelligence_Run_All.py"')

if __name__ == "__main__":
    main()
